import logging
from azure.storage.blob import BlobServiceClient, BlobClient, ContainerClient
import azure.functions as func

def main(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Python HTTP trigger function processed a request.')

    # Retrieve the blob path from query parameters
    blob_path = req.params.get('blobPath')
    
    if not blob_path:
        return func.HttpResponse("Please pass a blob path on the query string", status_code=400)

    try:
        # Initialize BlobServiceClient using your connection string
        connect_str = "your_connection_string"  # Replace with your Azure Storage account connection string
        blob_service_client = BlobServiceClient.from_connection_string(connect_str)

        # Define your container name
        container_name = "your_container_name"  # Replace with your container name

        # Create a BlobClient object using the blob path and container name
        blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_path)

        # Download the blob content
        download_stream = blob_client.download_blob()
        file_content = download_stream.readall()

        return func.HttpResponse(file_content, status_code=200)

    except Exception as e:
        logging.error(f"Error reading blob: {str(e)}")
        return func.HttpResponse("Failed to read the blob", status_code=500)